import{_ as t,o,c as a,a2 as s}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"RFC 0001 — Overlay shell variant","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0001-overlay-shell-variant.md","filePath":"rfcs/0001-overlay-shell-variant.md"}'),i={name:"rfcs/0001-overlay-shell-variant.md"};function n(l,e,r,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="rfc-0001-—-overlay-shell-variant" tabindex="-1">RFC 0001 — Overlay shell variant <a class="header-anchor" href="#rfc-0001-—-overlay-shell-variant" aria-label="Permalink to &quot;RFC 0001 — Overlay shell variant&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> Platform shell, manifest schema, generate script, <code>packages/ui</code><br><strong>Incorporated into plan:</strong> Yes — the design is recorded in SRS §3.8 (shell modes), §3.9 (dual composition), §5 (manifest <code>shell</code> enum), and CON-11 (root-plugin eligibility), with a decision-log row. The implementation is scheduled as Task 0.5.10 (overlay shell mode); the code changes in the &quot;Impact when accepted&quot; table land in that task.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Add a third <code>shell</code> mode to the plugin manifest — <code>overlay</code> — for plugins that should render as a dialog <strong>over</strong> the current page instead of navigating to a full page. Console and Account are the motivating cases: opening platform settings or your own profile should feel like a quick, dismissable layer on top of whatever you were doing, not a context-destroying navigation away from it.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;shell&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;default&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;minimal&quot;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;overlay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>The shell currently supports two modes (SRS §3.8):</p><ul><li><code>default</code> — full chrome; the plugin composes under the <code>(platform)/(plugins)</code> route group and inherits the sidebar.</li><li><code>minimal</code> — chrome-free full viewport (declared, not yet wired).</li></ul><p>Both are <strong>full-page</strong> modes. But some plugins are <em>interruptions</em>, not <em>destinations</em>. A user adjusting their timezone in Account, or an admin toggling a plugin in Console, is mid-task somewhere else — in Tasks, in Plainwrite&#39;s editor — and wants to return to exactly where they were. Today that round-trip costs two full navigations and loses scroll/UI state in the underlying plugin.</p><p>The same pattern recurs beyond chrome plugins: quick-capture tools, pickers, and settings-like third-party plugins all want &quot;open over the current view, do one thing, dismiss.&quot; Making <code>overlay</code> a manifest-level mode keeps the principle that <strong>Console and Account are plugins, not special cases</strong> — any plugin can opt in, and the shell treats them all identically.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li>Plugins compose at their <code>routePrefix</code> under a <code>shell</code>-selected route group; the composed segments are copies written by the generate script (CLAUDE.md hard rules, SRS §3.9). <code>shell: minimal</code> fails loudly in the generate script.</li><li>Console and Account live in the sidebar <strong>bottom section</strong> as hardcoded shell chrome (PLT-11); clicking them currently navigates to <code>/console</code> / <code>/account</code> as full pages.</li><li><code>adminOnly</code> routes are gated in the runtime middleware by URL prefix (PLT-03) — gating is independent of how the route is presented.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="_1-manifest" tabindex="-1">1. Manifest <a class="header-anchor" href="#_1-manifest" aria-label="Permalink to &quot;1. Manifest&quot;">​</a></h3><p>The <code>shell</code> enum gains a value:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Shell layout preference</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;default&quot; — full shell chrome (sidebar on desktop, header + footer on mobile).</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;minimal&quot; — shell chrome hidden entirely, content fills the viewport.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;overlay&quot; — renders as a dismissable dialog over the current page;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//             full-page fallback on direct/hard navigation.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">shell</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;default&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;minimal&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;overlay&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>This stays a single mutually-exclusive field rather than a separate <code>presentation</code> field — a plugin is exactly one of page-with-chrome, page-without-chrome, or overlay (see Alternatives).</p><h3 id="_2-routing-—-parallel-intercepting-routes" tabindex="-1">2. Routing — parallel + intercepting routes <a class="header-anchor" href="#_2-routing-—-parallel-intercepting-routes" aria-label="Permalink to &quot;2. Routing — parallel + intercepting routes&quot;">​</a></h3><p>Next.js App Router has a first-class pattern for &quot;modal over the current page&quot;: a <strong>parallel route slot</strong> rendered by the layout, populated via <strong>intercepting routes</strong> on soft navigation, with the real route as a full-page fallback on hard navigation. The proposal maps the existing copy-composition model onto it:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>runtime/app/(platform)/</span></span>
<span class="line"><span>├── layout.tsx                      # renders {children} and the {modal} slot</span></span>
<span class="line"><span>├── @modal/</span></span>
<span class="line"><span>│   ├── default.tsx                 # slot empty when no overlay is open</span></span>
<span class="line"><span>│   ├── layout.tsx                  # wraps slot content in the Dialog chrome</span></span>
<span class="line"><span>│   └── (.)console/…                # ← generate script: interception copy</span></span>
<span class="line"><span>└── (plugins)/</span></span>
<span class="line"><span>    └── console/…                   # ← generate script: full-page fallback copy</span></span></code></pre></div><p>For a <code>shell: overlay</code> plugin, the generate script composes the plugin&#39;s <code>app/</code> tree <strong>twice</strong>:</p><ol><li><strong>Interception copy</strong> → <code>(platform)/@modal/(.)&lt;routePrefix&gt;/</code> — an in-app (soft) navigation to the plugin renders inside the <code>@modal</code> slot, layered over whatever page is currently mounted. Navigation <em>between the plugin&#39;s own sub-routes</em> (e.g. <code>/console/users</code> → <code>/console/settings</code>) stays inside the slot, so multi-page plugins work as multi-page dialogs.</li><li><strong>Full-page fallback</strong> → <code>(platform)/(plugins)/&lt;routePrefix&gt;/</code> — exactly what <code>shell: default</code> produces today. A hard load (deep link, refresh, bookmark, middleware redirect after login) renders the plugin as a normal full page with the sidebar.</li></ol><p>Properties that fall out of this design for free:</p><ul><li><strong>URLs are real and unchanged.</strong> <code>/console/users</code> is the same URL whether it renders as an overlay or a page. Deep links, the middleware&#39;s <code>adminOnly</code> gating (PLT-03), and the login redirect all keep working with zero changes — gating happens by URL prefix before rendering mode is ever considered.</li><li><strong>The underlying page stays mounted.</strong> Closing the overlay (<code>router.back()</code>) returns to the exact prior state — no refetch, no lost scroll position.</li><li><strong>No plugin code changes.</strong> The plugin&#39;s <code>app/</code> tree is identical in both copies; a plugin author writes ordinary pages and flips one manifest field.</li></ul><p>The runtime owns the dialog chrome: <code>@modal/layout.tsx</code> wraps slot content in a <code>Dialog</code> (scrim, close affordance, Esc/scrim-click dismiss via <code>router.back()</code>, focus trap). Plugin content never implements its own modal shell.</p><h3 id="_3-shell-chrome-behaviour" tabindex="-1">3. Shell chrome behaviour <a class="header-anchor" href="#_3-shell-chrome-behaviour" aria-label="Permalink to &quot;3. Shell chrome behaviour&quot;">​</a></h3><ul><li>Sidebar bottom section (Console icon, Account avatar) keeps rendering plain <code>&lt;Link&gt;</code>s — interception turns those clicks into overlays automatically. No special-casing in the chrome.</li><li><strong>Mobile:</strong> the overlay renders as a full-screen sheet (same slot, responsive styling) — standard mobile modal behaviour. Header/footer chrome stays beneath it.</li><li><strong>Root plugin eligibility:</strong> the root plugin serves the platform root <code>/</code> as a full page, so <code>shell: overlay</code> plugins are <strong>not eligible</strong> as root plugin. CON-11&#39;s eligibility rule (&quot;installed, enabled, non-adminOnly&quot;) gains &quot;non-overlay&quot;.</li></ul><h3 id="_4-packages-ui" tabindex="-1">4. <code>packages/ui</code> <a class="header-anchor" href="#_4-packages-ui" aria-label="Permalink to &quot;4. \`packages/ui\`&quot;">​</a></h3><p>New primitives (also independently useful):</p><ul><li><strong><code>Dialog</code></strong> — scrim + panel, sizes (<code>sm</code> / <code>md</code> / <code>lg</code> / <code>full</code>), Esc and scrim-click dismissal, focus trap, <code>--sv-*</code> tokens only.</li><li><strong><code>Sheet</code></strong> — the mobile full-screen variant (may be a <code>Dialog</code> responsive mode rather than a separate component — implementation detail).</li></ul><h3 id="_5-generate-script" tabindex="-1">5. Generate script <a class="header-anchor" href="#_5-generate-script" aria-label="Permalink to &quot;5. Generate script&quot;">​</a></h3><ul><li><code>shell: overlay</code> → compose the two copies described above and emit the registry entry with the mode (the shell may want it for chrome hints).</li><li><code>shell: minimal</code> remains unwired and keeps failing loudly — this RFC does not implement it, but the route-group mapping it implies (<code>default</code> / <code>minimal</code> / <code>overlay</code> → three compose targets) should be kept coherent when either lands.</li></ul><h2 id="impact-accepted-—-srs-tasks-incorporated-code-lands-in-task-0-5-10" tabindex="-1">Impact (accepted — SRS/tasks incorporated; code lands in Task 0.5.10) <a class="header-anchor" href="#impact-accepted-—-srs-tasks-incorporated-code-lands-in-task-0-5-10" aria-label="Permalink to &quot;Impact (accepted — SRS/tasks incorporated; code lands in Task 0.5.10)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Where</th><th>Change</th></tr></thead><tbody><tr><td><code>packages/manifest</code></td><td><code>shell</code> enum gains <code>&#39;overlay&#39;</code>; tests; <strong>minor</strong> version bump.</td></tr><tr><td>SRS §3.8 / §5</td><td>Document the third mode; update the shell-layout prose and manifest reference; decision-log entry.</td></tr><tr><td>SRS §4</td><td>Extend CON-11 root-plugin eligibility with &quot;non-overlay&quot;.</td></tr><tr><td><code>scripts/generate-registry.ts</code></td><td>Dual composition for overlay plugins (interception + fallback copies).</td></tr><tr><td><code>runtime/app/(platform)/</code></td><td><code>@modal</code> slot: <code>default.tsx</code>, dialog <code>layout.tsx</code>; layout renders the slot.</td></tr><tr><td><code>packages/ui</code></td><td><code>Dialog</code> (and mobile sheet behaviour).</td></tr><tr><td><code>docs/plugins/console.md</code>, <code>docs/plugins/account.md</code></td><td>Manifests flip to <code>shell: &quot;overlay&quot;</code>; UI sections updated.</td></tr><tr><td><code>docs/roadmap.md</code></td><td>A wiring task (suggested: land with or just before the Account plugin task, so Account ships overlay-first and Console migrates in the same change).</td></tr><tr><td><code>CLAUDE.md</code></td><td>Hard-rule note: the shell route-group mapping gains the overlay compose target.</td></tr></tbody></table><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Client-side modal rendering</strong> (portal/iframe that fetches the plugin route): loses RSC rendering and layout nesting, double-fetches, and reimplements routing the App Router already provides. Rejected.</li><li><strong>Hardcode Console/Account as chrome dialogs</strong> (not manifest-driven): violates the &quot;Console is a plugin, not a special case&quot; decision (SRS decision log) and gives third-party plugins no path to the same behaviour. Rejected.</li><li><strong>A separate <code>presentation</code> manifest field</strong> (<code>page</code> | <code>overlay</code>) alongside <code>shell</code>: creates an invalid combination surface (<code>minimal</code> + <code>overlay</code>?) for no benefit — the three modes are mutually exclusive presentations of one plugin. Rejected in favour of extending the existing enum.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Deep-link rendering choice.</strong> A hard load of <code>/console</code> renders the full-page fallback (proposed). Alternative: render the root plugin with the overlay already open on top. The fallback is simpler and ships first; &quot;overlay restored over root&quot; can be revisited later without breaking URLs.</li><li><strong>Per-plugin size hint.</strong> <s>Should the manifest carry a dialog size or does the runtime pick one size for all overlays in v1?</s> <strong>Resolved (post-0.5.09):</strong> the manifest carries an optional <code>shellConfig.overlaySize</code> (<code>sm</code> | <code>md</code> | <code>lg</code>, default <code>lg</code>); the <code>@modal</code> slot resolves it from the selected interception segment.</li><li><strong>Unsaved-state dismissal.</strong> Esc/scrim-click closes the dialog; a plugin mid-form may want to confirm. Does v1 accept close-loses-state (plugins should save eagerly, as Account does), or do we need an SDK hook to block dismissal? Recommendation: accept in v1; revisit with evidence.</li><li><strong>History stacking.</strong> <s>Navigating between several sub-routes inside an overlay builds history entries; closing via <code>router.back()</code> then steps through them.</s> <strong>Resolved (post-0.5.09):</strong> intra-overlay tab/section links use <code>&lt;Link replace&gt;</code>, so the overlay occupies a single history entry and one <code>router.back()</code> dismisses straight to the pre-overlay page. Documented as a convention for third-party overlay plugins in <code>docs/plugin-development.md</code>.</li><li><strong>Interception edge cases.</strong> Confirm interception behaves correctly across the <code>(plugins)</code> route-group boundary and with the composed-copies model on the current Next.js version (prototype before accepting).</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Accept RFC → apply the &quot;Impact when accepted&quot; table top to bottom (manifest first, then runtime wiring, then spec/doc updates — one task).</li><li>Account ships with <code>shell: &quot;overlay&quot;</code>; Console migrates from <code>default</code> in the same change.</li><li><code>overlay</code> becomes available to third-party plugins as part of the public manifest contract from the next <code>@sovereignfs/manifest</code> minor release.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft.</td></tr><tr><td>1.0</td><td>Jun 2026</td><td>Accepted; incorporated into SRS (§3.8/§3.9/§5/CON-11 + decision log) and Task 0.5.10.</td></tr><tr><td>1.1</td><td>Jun 2026</td><td>Post-implementation: resolved open questions 2 (manifest <code>shellConfig.overlaySize</code>) and 4 (<code>router.replace</code> for intra-overlay navigation).</td></tr><tr><td>1.2</td><td>Jun 2026</td><td>Post-implementation: the <code>Dialog</code> scrim insets its left edge past the platform sidebar (<code>--sv-dialog-inset-left</code>), so overlay dialogs start at the sidebar&#39;s right edge and leave the rail visible.</td></tr></tbody></table>`,43)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
